-- {"operators": "INNER_JOIN,AGGREGATE,HAVING,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER,ORDER_LINE", "ducklake": true}
WITH big_orders AS (SELECT OL_W_ID, OL_D_ID, OL_O_ID, SUM(OL_AMOUNT) AS total FROM dl.ORDER_LINE GROUP BY OL_W_ID, OL_D_ID, OL_O_ID HAVING SUM(OL_AMOUNT) > 100) SELECT c.C_W_ID, c.C_ID, c.C_LAST, SUM(b.total) AS spent FROM dl.CUSTOMER c JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID JOIN big_orders b ON o.O_W_ID = b.OL_W_ID AND o.O_D_ID = b.OL_D_ID AND o.O_ID = b.OL_O_ID GROUP BY c.C_W_ID, c.C_ID, c.C_LAST;
